// src/components/CategoryItem/index.jsx
import React from 'react';
import { Link } from 'react-router-dom'; // Используем Link для навигации
import { getImageUrl } from '../../utils/fixUrl'; // Импорт хелпера для URL
import s from './CategoryItem.module.css';

const CategoryItem = ({ id, title, image }) => {
  const imageUrl = getImageUrl(image);

  return (
    // При клике переходим на страницу товаров этой категории: /categories/1, /categories/2 и т.д.
    <Link to={`/categories/${id}`} className={s.item}>
      <div className={s.imageWrapper}>
        <img src={imageUrl} alt={title} className={s.image} />
      </div>
      <p className={s.title}>{title}</p>
    </Link>
  );
};

export default CategoryItem;
